query:
CREATE TABLE IF NOT EXISTS `clients` (
	`id` varchar(36) NOT NULL,
	`admin_id` varchar(36) NOT NULL,
	`nome` varchar(255) NOT NULL,
	`telefone` varchar(20),
	`email` varchar(255),
	`ativo` boolean NOT NULL DEFAULT true,
	`data_criacao` bigint NOT NULL,
	`data_atualizacao` bigint NOT NULL,
	CONSTRAINT `clients_id` PRIMARY KEY(`id`)
);
CREATE TABLE IF NOT EXISTS `transactions` (
	`id` varchar(36) NOT NULL,
	`admin_id` varchar(36) NOT NULL,
	`cliente_id` varchar(36) NOT NULL,
	`tipo` varchar(20) NOT NULL,
	`valor` int NOT NULL,
	`descricao` text NOT NULL,
	`data` bigint NOT NULL,
	`data_criacao` bigint NOT NULL,
	`data_atualizacao` bigint NOT NULL,
	CONSTRAINT `transactions_id` PRIMARY KEY(`id`)
);
CREATE INDEX IF NOT EXISTS `admin_id_idx` ON `clients` (`admin_id`);
CREATE INDEX IF NOT EXISTS `nome_idx` ON `clients` (`nome`);
CREATE INDEX IF NOT EXISTS `admin_id_idx_tx` ON `transactions` (`admin_id`);
CREATE INDEX IF NOT EXISTS `cliente_id_idx` ON `transactions` (`cliente_id`);
CREATE INDEX IF NOT EXISTS `data_idx` ON `transactions` (`data`);

